import logo from "./logo.svg";
import "./App.css";
import TodoItems from "./components/TodoItems";
import FilterTasks from "./components/FilterTasks";
import { useState, useEffect } from "react";
import Spinner from "./components/Spinner";
import AddNewTask from "./components/AddNewTask";

function App() {
  const [tasks, setTasks] = useState([]);
  const[loading, setLoading]= useState(true)
  const [inputTitle, setInputTitle] = useState('');
  const [inputDescription, setInputDescription] = useState('');
  const [addTask, setAddTask]= useState(true)


  const url =
    "https://todo-app-7ea63-default-rtdb.europe-west1.firebasedatabase.app/.json";
  useEffect(() => {
    fetch(url)
      .then((res) => res.json())
      .then((result) => {
        setTasks(Object.values(result.tasks));
        setLoading(false)
      });
  }, []);



const titleChangeHandler = (event) =>{
  setInputTitle(event.target.value)
}

const descriptionChangeHandler = (event) =>{
  setInputDescription(event.target.value)
}



  const addTaskHandler = (event)=>{
    event.preventDefault();
    console.log(inputDescription)
    console.log(inputTitle)
    setTasks([{
      ...tasks,
      description:inputDescription,
      name:inputTitle,
      id:'t3',
      "isDone": false,
      "isImportant": true,

    }])


  }


  return (
    <main className="App">
      <AddNewTask titleChangeHandler={titleChangeHandler} descriptionChangeHandler={descriptionChangeHandler} inputTitle={inputTitle} addTaskHandler={addTaskHandler} />
      <Spinner />
      <TodoItems task={tasks} loading={loading}></TodoItems>
      <FilterTasks />
    </main>
  );
}

export default App;
